const API = '';
const LS_USER = 'humanx_public_user_v1';
const LS_ADMIN = 'humanx_admin_token_v1';

let claims = [];
let evidenceVault = [];
let truths = [];
let beliefSnapshots = [];
let graphStatus = null;
let selected = null;
let mode = 'home';
let lastPacket = '';
let lastPacketIsFallback = false;
let lastPacketClaimId = '';
let live = false;
let user = null;
let lastBeliefSnapshot = null;
let reviewQueue = { claims: [], truths: [], review: [], archived_total: 0, archived_claims: 0, archived_truths: 0 };
let inspectedReviewItem = null;
let reviewStateFilter = 'review';
let reviewAuditOpen = false;
let pendingRejectReviewId = null;
let pendingCleanupReviewId = null;
let attachingEvidenceId = null;

function esc(s) {
  return String(s ?? '').replace(/[&<>"']/g, m => ({
    '&': '&amp;',
    '<': '&lt;',
    '>': '&gt;',
    '"': '&quot;',
    "'": '&#039;'
  }[m]));
}
function toast(t) { const e=document.createElement('div'); e.className='toast'; e.textContent=t; document.body.appendChild(e); setTimeout(()=>e.remove(),1800); }
function hxModal({title,body,confirmLabel='Submit',cancelLabel='Cancel',onConfirm,onCancel}={}) {document.getElementById('hx-modal')?.remove();const el=document.createElement('div');el.id='hx-modal';el.className='hx-modal-overlay';el.setAttribute('role','dialog');el.setAttribute('aria-modal','true');el.innerHTML=`<div class="hx-modal-panel">${title?`<h3 class="hx-modal-title">${esc(title)}</h3>`:''}<div class="hx-modal-body">${body||''}</div><div class="hx-modal-actions"><button class="primary hx-modal-confirm">${esc(confirmLabel)}</button><button class="hx-modal-cancel">${esc(cancelLabel)}</button></div></div>`;document.body.appendChild(el);const close=()=>{el.remove();document.removeEventListener('keydown',onKey);};const onKey=e=>{if(e.key==='Escape'){close();if(onCancel)onCancel();}};document.addEventListener('keydown',onKey);el.querySelector('.hx-modal-confirm').onclick=()=>{if(onConfirm)onConfirm(close);};el.querySelector('.hx-modal-cancel').onclick=()=>{close();if(onCancel)onCancel();};el.addEventListener('click',e=>{if(e.target===el){close();if(onCancel)onCancel();}});setTimeout(()=>el.querySelector('textarea,input')?.focus(),50);return close;}
function headers(){return{'content-type':'application/json','x-humanx-user':user?.id||''}}
function adminToken(){return localStorage.getItem(LS_ADMIN)||''}
function adminHeaders(){return {...headers(),'x-humanx-admin':adminToken()}}
async function api(path,opts={}){const r=await fetch(API+path,{...opts,headers:{...headers(),...(opts.headers||{})}});const data=await r.json().catch(()=>({}));if(!r.ok)throw new Error(data.message||data.error||'Request failed');return data}
function localUser(){let u=JSON.parse(localStorage.getItem(LS_USER)||'null');if(!u){u={id:'usr_'+crypto.randomUUID().replaceAll('-','').slice(0,18),handle:'anon-'+Math.random().toString(36).slice(2,8)};localStorage.setItem(LS_USER,JSON.stringify(u))}return u}
function sourceLink(url){if(!url)return'';const safe=esc(url);return`<p class="small source"><a href="${safe}" target="_blank" rel="noopener noreferrer">${safe}</a></p>`}
function cleanStance(v){v=String(v||'support').toLowerCase().trim();return v==='pressure'?'pressure':'support'}
function cleanClaimLabel(s){return String(s||'').replace(/\s*[—-]\s*this statement reflects reality consistently enough to survive evidence and repeatable pressure testing\.?/ig,'').replace(/\s*[—-]\s*X\s*$/,'').trim()}
function isFullBeliefProfile(s){return String(s?.source||'').includes('standalone-humanx-belief-engine')||String(s?.engineVersion||'').includes('humanx-belief-engine')||String(s?.label||'').includes('Belief Engine Profile')}
function parseAnalysis(text){try{const o=JSON.parse(String(text||''));if(o&&typeof o==='object'&&(o.verdict||o.strongest_support||o.strongest_pressure||o.missing_tests))return o}catch{}return null}
function shortText(s,n=420){s=String(s||'').trim();return s.length>n?s.slice(0,n)+'…':s}
function looksLikeJson(s){const t=String(s||'').trim();if(t.length<30)return false;if(/^[\[{]/.test(t)&&/[":,]/.test(t.slice(0,100)))return true;if(t.split('":').length>4)return true;if(/runpack_version|evidence_score|aip_version|strongest_support|packet_type/.test(t))return true;return false;}
function evidenceBodyHtml(text,maxChars=300){const t=String(text||'').trim();if(!t)return'';if(looksLikeJson(t)){const preview=t.replace(/[{}\[\],"]/g,' ').replace(/\s+/g,' ').trim().slice(0,120);return`<div class="ev-json-body"><span class="pill ev-json-chip">AI / JSON output</span><p class="small ev-body-preview">${esc(preview)}…</p><details class="ev-body-details"><summary>Show full text</summary><pre class="ev-body-full">${esc(t)}</pre></details></div>`;}return`<p class="small ev-body-text">${esc(shortText(t,maxChars))}</p>`;}
function listBits(arr){return Array.isArray(arr)?`<ul>${arr.slice(0,4).map(x=>`<li>${esc(x)}</li>`).join('')}</ul>`:''}
async function boot(){user=localUser();document.getElementById('who').textContent=user.handle;try{const h=await api('/api/health');live=h.mode==='d1-live';setStatus(live?'D1 live':'Demo fallback',live);try{const s=await api('/api/session',{method:'POST',body:JSON.stringify(user)});if(s.user){user={...user,...s.user};document.getElementById('who').textContent=user.handle;localStorage.setItem(LS_USER,JSON.stringify(user))}}catch{}await Promise.all([loadGraphStatus(),loadClaims(false)]);render()}catch(e){setStatus('Backend unreachable',false,true);renderError(e)}}
function setStatus(t,ok,bad=false){document.getElementById('status').textContent=t;const d=document.getElementById('dot');d.className='dot '+(bad?'bad':ok?'live':'')}
async function loadGraphStatus(){try{graphStatus=await api('/api/graph-status')}catch{graphStatus=null}}
function q(){return encodeURIComponent(document.getElementById('search')?.value||'')}
async function loadClaims(doRender=true){try{const f=encodeURIComponent(document.getElementById('filter')?.value||'all');const data=await api(`/api/claims?q=${q()}&status=${f}`);claims=data.claims||[];if(data.warning)setStatus(data.warning,false);if(doRender)render()}catch(e){renderError(e)}}
async function loadEvidenceVault(){const data=await api(`/api/evidence-vault?q=${q()}`);evidenceVault=data.evidence||[]}
async function loadTruths(){const data=await api(`/api/truths?q=${q()}`);truths=data.truths||[]}
async function loadBeliefSnapshots(){const data=await api('/api/belief-snapshots?limit=30');beliefSnapshots=data.snapshots||[]}
async function loadReviewQueue(){const data=await api('/api/review',{headers:adminHeaders()});reviewQueue={claims:data.claims||[],truths:data.truths||[],review:data.review||[],archived_total:data.archived_total||0,archived_claims:data.archived_claims||0,archived_truths:data.archived_truths||0};return reviewQueue}
async function searchCurrent(){if(mode==='vault')return renderVault();if(mode==='truths')return renderTruths();if(mode==='review')return renderReview();if(mode==='belief')return renderBelief();if(mode==='drift')return renderDrift();if(mode==='home')return renderHome();await loadClaims(true)}
function setMode(m){mode=m;if(m!=='export')selected=null;document.body.classList.remove('study-mode');document.body.className=(document.body.className||'').split(' ').filter(c=>!c.startsWith('mode-')).join(' ').trim()+' mode-'+m;document.querySelectorAll('.tab').forEach(x=>x.classList.remove('active'));document.getElementById('tab-'+m)?.classList.add('active');render()}
function cls(s){if(s==='Proven'||String(s).includes('Supported')||String(s).includes('rising'))return'b-green';if(String(s).includes('Disproven')||String(s).includes('Collapse')||String(s).includes('falling'))return'b-red';if(s==='Plausible')return'b-blue';return'b-yellow'}
function meter(n,v){v=Math.max(0,Math.min(100,Number(v||0)));return`<div class="meter"><span>${n} <b class="meter-val">${v}</b></span><div class="bar"><div class="fill" style="width:${v}%"></div></div></div>`}
function deltaMeter(n,v){const sign=v>0?'+':'';return`<div class="meter"><span>${n} ${sign}${esc(v)}</span><div class="bar"><div class="fill" style="width:${Math.min(100,Math.abs(Number(v||0)))}%"></div></div></div>`}
function graphVal(v){return v===null||v===undefined?'ERR':v}
function graphBox(){const g=graphStatus?.graph||{};const items=[['Claims',g.claims],['Evidence',g.evidence],['Truths',g.truths],['Links',g.evidenceClaimLinks],['Votes',g.claimVotes],['Reports',g.reports]];const err=graphStatus&&graphStatus.ok===false?`<p class="small error">Graph schema warning: ${esc(Object.keys(graphStatus.errors||{}).join(', ')||'unknown')}</p>`:'';return`<div class="graph-status">${items.map(([k,v])=>`<span><b>${esc(graphVal(v))}</b><small>${k}</small></span>`).join('')}</div>${err}`}
function helperText(){if(mode==='drift')return'<p class="small">Drift tracks how beliefs change across sessions.</p><p class="small"><b>Save as Truth</b> — records a repeated certainty for the Truths list.<br><b>Send to Claim Review</b> — creates a public, pressure-testable claim.</p><p class="small review-first-note">Both actions enter Review before going public.</p><p class="small review-first-note">Full profiles carry 77-statement forensic scores. Quick records are lightweight snapshots.</p>';if(mode==='belief')return'<p class="small">Belief Engine: record belief structure, source, identity load, inheritance, pressure, and what could change your mind.</p>';if(mode==='home')return'<p class="small"><b>Beliefs → Truths → Claims → Evidence → RunPack</b></p><p class="small review-first-note">New submissions enter Review before becoming public.</p><p class="small">Pseudonymous. No email required.</p>';if(mode==='vault')return'<p class="small">Reusable sources, records, and evidence items. Each can be attached to multiple claims as support or pressure.</p><p class="small"><b>Study Linked Claim</b> opens the connected claim. <b>Attach to Claim</b> links an item into another claim.</p>';if(mode==='truths')return'<p class="small"><b>Truths</b> are statements that circulate as fact — slogans, doctrines, inherited certainties, widely-repeated beliefs.</p><p class="small review-first-note">HumanX records what is asserted, not whether it is correct. Recording a Truth does not verify it.</p><p class="small"><b>Send to Claim Review</b> converts a truth into a pressure-testable public claim.</p><p class="small review-first-note">Added truths enter Review before going public.</p>';if(mode==='review'){const at=reviewQueue.archived_total||0;const ac=reviewQueue.archived_claims||0;const atr=reviewQueue.archived_truths||0;const archivedChip=at>0?`<div class="review-ctx-archived"><span class="review-ctx-archived-label">Archived</span><span class="review-ctx-archived-n">${at}</span><span class="review-ctx-archived-detail">${ac&&atr?`claims ${ac} · truths ${atr}`:ac?`claims ${ac}`:atr?`truths ${atr}`:''}</span><span class="review-ctx-archived-note">not in queue</span></div>`:'';return'<p class="small"><b>Pending</b> items are not public. <b>Approve</b> makes an item public. <b>Reject</b> keeps it private.</p><p class="small review-first-note"><b>Archive</b> is only for rejected smoke/test artefacts.</p><p class="small review-first-note">Report count reflects user flags — not proof of wrongdoing.</p>'+archivedChip;}if(mode==='export')return selected?`<p class="small"><b>Selected claim</b><br>${esc(cleanClaimLabel(selected.claim))}</p><p class="small">Build the RunPack, then copy or download it and paste into any AI. No owner API credits used.</p><p class="small review-first-note">Exporting does not publish anything.</p>`:'<p class="small">No claim selected.</p><p class="small">Open a claim from the <b>Claims</b> tab → <b>Study</b> it → click <b>Build RunPack</b>. Then return here to copy or download the packet.</p>';if(mode==='submit')return'<p class="small">A claim is a precise, testable public statement. Scores reflect what evidence has been submitted — not an automatic verdict.</p><p class="small review-first-note">New claims enter Review before becoming public.</p>';return'<p class="small">Browse public claims. Open Study to investigate, vote on, and attach evidence to any claim.</p><p class="small review-first-note">Badges: Public · Pending Review · Rejected · Reported · Archived.</p><p class="small review-first-note">Use the search bar and verdict filter to narrow the list.</p>'}
function render(){if(mode==='home')return renderHome();if(mode==='belief')return renderBelief();if(mode==='drift')return renderDrift();if(mode==='submit')return renderSubmit();if(mode==='vault')return renderVault();if(mode==='truths')return renderTruths();if(mode==='review')return renderReview();if(mode==='export')return renderExport();renderArena()}
function renderHome(){document.body.classList.remove('study-mode');document.getElementById('casefile').innerHTML=helperText();document.getElementById('side-tools').style.display='none';const g=graphStatus?.graph||{};const sv=v=>v===null||v===undefined?'unknown':String(v);document.getElementById('main').innerHTML=`<div class="cc-layout"><section class="cc-hero"><div class="cc-hero-left"><span class="badge b-green">working system</span><h1 class="cc-title">HumanX</h1><p class="cc-subtitle">Map personal belief. Record what gets repeated as fact. Pressure-test public claims with evidence. HumanX organises what people assert — it does not decide what is true.</p><p class="cc-hero-statusline"><span>${esc(user?.handle||'anon')}</span><span class="cc-sep">·</span><span>${esc(live?'D1 live':(graphStatus!==null?'demo':'offline'))}</span><span class="cc-sep">·</span><span>${claims.length>0?claims.length:sv(g.claims)} claims</span><span class="cc-sep">·</span><span>${sv(g.truths)} truths</span><span class="cc-sep">·</span><span>${sv(g.evidence)} evidence</span></p><div class="pipeline-banner"><div class="pipeline-stage"><b>Beliefs</b><span>personal structure</span></div><div class="pipeline-arrow">→</div><div class="pipeline-stage"><b>Truths</b><span>repeated certainties</span></div><div class="pipeline-arrow">→</div><div class="pipeline-stage"><b>Claims</b><span>public statements</span></div><div class="pipeline-arrow">→</div><div class="pipeline-stage"><b>Evidence</b><span>support &amp; challenge</span></div><div class="pipeline-arrow">→</div><div class="pipeline-stage"><b>RunPack</b><span>export for AI analysis</span></div></div></div><div class="cc-hero-right">${graphBox()}</div></section><section class="cc-section"><h2 class="cc-section-head">Actions</h2><div class="cc-card-grid"><button class="cc-card cc-card-primary" onclick="location.href='/apps/humanx-belief-engine/'"><span class="cc-card-icon">◉</span><b>Belief Engine</b><span class="cc-card-desc">Full 77-statement forensic belief profile. Maps belief structure, source, identity load, inheritance, pressure, and what could change your mind.</span><span class="cc-card-when">When: starting from personal belief before making a public claim.</span><span class="cc-card-action">Open Belief Engine →</span></button><button class="cc-card" onclick="setMode('drift')"><span class="cc-card-icon">〜</span><b>Drift</b><span class="cc-card-desc">View full Belief Engine profiles and quick belief records over time. Measure belief drift across sessions.</span><span class="cc-card-when">When: comparing beliefs over time or reviewing saved profile snapshots.</span><span class="cc-card-action">View Drift →</span></button><button class="cc-card" onclick="setMode('submit')"><span class="cc-card-icon">✦</span><b>Submit Claim</b><span class="cc-card-desc">Submit one precise, pressure-testable public statement. Pseudonymous. Enters moderation before going live.</span><span class="cc-card-when">When: you have a belief or truth ready to test publicly.</span><span class="cc-card-action">Submit Claim →</span></button><button class="cc-card" onclick="setMode('arena')"><span class="cc-card-icon">⊞</span><b>Browse Claims</b><span class="cc-card-desc">Open, study, vote on, and attach evidence to public claims. Enter Study mode for evidence, pressure, tests, and analysis.</span><span class="cc-card-when">When: reviewing, attacking, or supporting existing claims.</span><span class="cc-card-action">Browse Claims →</span></button><button class="cc-card" onclick="setMode('vault')"><span class="cc-card-icon">◈</span><b>Evidence Vault</b><span class="cc-card-desc">Reusable sources, documents, datasets, and test records. Attach vault items across multiple claims without duplication.</span><span class="cc-card-when">When: browsing reusable evidence or tracing how a source is used across claims.</span><span class="cc-card-action">Evidence Vault →</span></button><button class="cc-card" onclick="setMode('truths')"><span class="cc-card-icon">◇</span><b>Truths</b><span class="cc-card-desc">Statements that circulate as fact — slogans, doctrines, inherited certainties. HumanX records what is asserted, not whether it is correct. Convert any truth into a pressure-testable claim.</span><span class="cc-card-when">When: recording a widely repeated belief or promoting a truth to a public claim.</span><span class="cc-card-action">View Truths →</span></button><button class="cc-card" onclick="setMode('export')"><span class="cc-card-icon">⊡</span><b>RunPack</b><span class="cc-card-desc">Generate a structured analysis packet from any claim. Paste into any AI for external analysis. No owner API credits used.</span><span class="cc-card-when">When: ready to export a claim for AI analysis after evidence and pressure are attached.</span><span class="cc-card-action">RunPack Export →</span></button></div></section></div>`}
async function renderBelief(){location.href='/apps/humanx-belief-engine/'}
async function renderDrift(){document.body.classList.remove('study-mode');document.getElementById('casefile').innerHTML=helperText();document.getElementById('side-tools').style.display='none';document.getElementById('main').innerHTML='<div class="panel"><h2>Loading Drift…</h2></div>';try{await loadBeliefSnapshots()}catch(e){beliefSnapshots=[]}const ordered=[...beliefSnapshots].sort((a,b)=>(a.createdAt||0)-(b.createdAt||0));const profiles=ordered.filter(isFullBeliefProfile);const quick=ordered.filter(s=>!isFullBeliefProfile(s));document.getElementById('main').innerHTML=`<div class="drift-header"><h2>Drift</h2><span class="badge b-blue">${profiles.length} full profile${profiles.length===1?'':'s'} · ${quick.length} quick record${quick.length===1?'':'s'}</span></div>${profiles.length?renderProfileDrift(profiles):'<div class="panel drift-empty-panel"><div class="drift-empty-type-head"><h3>Full Belief Engine Profiles</h3><span class="badge b-blue">77 statements</span></div><p class="small">No full profile saved yet. Complete the Belief Engine and click <b>Send to HumanX</b> to record one.</p><button class="primary" onclick="location.href=\'/apps/humanx-belief-engine/\'">Open Belief Engine</button></div>'}${quick.length?`<div class="drift-section-head"><h3>Quick Belief Records</h3><span class="badge">${quick.length} record${quick.length===1?'':'s'}</span><span class="drift-section-note">lightweight snapshots · not full 77-statement profiles</span></div><div class="grid">${quick.map(beliefSnapshotCard).join('')}</div>`:''}${!ordered.length?'<div class="panel"><div class="empty-state"><p>No belief snapshots yet.</p><p class="small">Open the Belief Engine, complete a profile, and click <b>Send to HumanX</b> to save it here. Saved profiles can be promoted to a Truth or public Claim.</p><div class="actions" style="margin-top:10px"><button class="primary" onclick="location.href=\'/apps/humanx-belief-engine/\'">Open Belief Engine</button></div></div></div>':''}`}
function renderProfileDrift(profiles){const first=profiles[0],last=profiles[profiles.length-1];const ds=(last.stabilityScore||0)-(first.stabilityScore||0),doo=(last.opennessScore||0)-(first.opennessScore||0),dp=(last.pressureScore||0)-(first.pressureScore||0),dc=(last.contradictionCount||0)-(first.contradictionCount||0);const verdict=profiles.length<2?'profile baseline':dp>20?'pressure rising':ds>20?'stability rising':doo>20?'openness rising':ds<-20?'stability falling':'mixed / stable profile drift';const comparePanel=profiles.length>1?`<div class="panel drift-compare-panel"><p class="small drift-compare-label">Drift: <b>${esc(first.label||'earliest')}</b> → <b>${esc(last.label||'latest')}</b></p><div class="meters">${deltaMeter('Stability',ds)}${deltaMeter('Openness',doo)}${deltaMeter('Pressure',dp)}${deltaMeter('Contradictions',dc)}</div><p class="small">${driftText(ds,doo,dp,dc)}</p></div>`:'<p class="small drift-baseline-note">One profile saved — add more to measure drift over time.</p>';return`<div class="drift-section-head"><h3>Full Belief Engine Profiles</h3><span class="badge ${cls(verdict)}">${esc(verdict)}</span></div>${comparePanel}<div class="grid">${profiles.map(beliefSnapshotCard).join('')}</div>`}
function driftText(ds,doo,dp,dc){const bits=[];if(ds>10)bits.push('belief stability increased');if(ds<-10)bits.push('belief stability weakened');if(doo>10)bits.push('openness increased');if(doo<-10)bits.push('openness narrowed');if(dp>10)bits.push('pressure increased');if(dp<-10)bits.push('pressure reduced');if(dc>0)bits.push('more contradictions were detected');if(dc<0)bits.push('fewer contradictions were detected');return bits.length?bits.join('; ')+'.':'No major movement detected yet.'}
function beliefSnapshotMini(s){return`<span class="badge b-yellow">${esc(s.dominantPattern||s.source||'belief')}</span><h3>${esc(s.label||'Belief record')}</h3><p class="small">${esc(new Date(s.createdAt||Date.now()).toLocaleString())}</p><div class="meters">${meter('Stability',s.stabilityScore)}${meter('Open',s.opennessScore)}${meter('Pressure',s.pressureScore)}</div><p class="small">${esc(shortText(s.summary||'',300))}</p>`}
function beliefSnapshotCard(s){const full=isFullBeliefProfile(s);return`<article class="card belief-card ${full?'belief-card-full':'belief-card-quick'}"><div class="belief-card-badges"><span class="badge ${full?'b-blue':'b-yellow'}">${esc(full?'full profile':(s.dominantPattern||s.source||'belief'))}</span>${full?'<span class="badge b-blue">77 statements</span>':''}</div><h3>${esc(s.label||'Belief record')}</h3><p class="small">${esc(new Date(s.createdAt||Date.now()).toLocaleString())}</p><div class="meters">${meter('Stability',s.stabilityScore)}${meter('Open',s.opennessScore)}${meter('Pressure',s.pressureScore)}</div><p class="small">${esc(shortText(s.summary||'',260))}</p><div class="actions"><button onclick="promoteBelief('${esc(s.id)}','truth')" title="Records this belief as a widely-repeated Truth statement. Enters moderation before going public.">Save as Truth</button><button class="primary" onclick="promoteBelief('${esc(s.id)}','claim')" title="Creates a public, pressure-testable Claim from this belief. Enters moderation before going public.">Send to Claim Review</button></div><p class="small drift-promote-note">→ both actions enter Review before going public</p></article>`}
function n(id){return Number(document.getElementById(id)?.value||0)}function v(id){return document.getElementById(id)?.value||''}
function buildBeliefSnapshot(){return{}}
function classifyBelief(){return'open belief'}
function beliefPreview(){}
async function saveBeliefMirror(){location.href='/apps/humanx-belief-engine/'}
async function promoteBelief(snapshotId,target){try{const data=await api('/api/belief-promote',{method:'POST',body:JSON.stringify({snapshotId,target})});if(target==='truth'){toast(data.existing?'Truth reinforced — already in Truths.':'Truth promoted to Review. It will appear publicly after approval.');mode='truths';document.querySelectorAll('.tab').forEach(x=>x.classList.remove('active'));document.getElementById('tab-truths')?.classList.add('active');await loadGraphStatus();await renderTruths();return}if(data.claimId){toast(data.existing?'Existing claim opened in Study.':'Claim promoted to Review. It will appear publicly after approval.');mode='arena';document.querySelectorAll('.tab').forEach(x=>x.classList.remove('active'));document.getElementById('tab-arena')?.classList.add('active');await loadGraphStatus();await loadClaims(false);await selectClaim(data.claimId);return}toast('Belief promoted')}catch(e){toast(e.message||(target==='truth'?'Truth promotion failed.':'Claim promotion failed.'))}}
function renderArena(){document.body.classList.remove('study-mode');document.getElementById('casefile').innerHTML=helperText();document.getElementById('side-tools').style.display='none';document.getElementById('main').innerHTML=`<div class="section-head"><h2>Claims</h2>${graphBox()}</div><div class="grid">${claims.map(c=>card(c,true)).join('')||'<div class="panel"><div class="empty-state"><p>No claims match this view.</p><p class="small">Claims are public, testable statements with evidence and pressure attached. Use the <b>Submit</b> tab to add one, or adjust the verdict filter above.</p><div class="actions" style="margin-top:8px"><button class="primary" onclick="setMode(\'submit\')">Submit Claim</button><button onclick="document.getElementById(\'filter\').value=\'all\';loadClaims(true)">Show all</button></div></div></div>'}</div>`}
function card(c,actions=false){const votes=`<span title="Believe">▲ ${esc(c.beliefYes||0)}</span><span title="Reject">▼ ${esc(c.beliefNo||0)}</span><span title="Unsure">~ ${esc(c.uncertainty||0)}</span>${c.contradictions?`<span class="claim-pressure-chip" title="Pressure points">⊘ ${esc(c.contradictions)} pressure</span>`:''}`;const metaParts=[c.type,c.handle?'by '+c.handle:''].filter(Boolean).map(esc).join(' · ');return`<article class="card claim-card"><div class="claim-card-head"><span class="badge ${cls(c.status)}">${esc(c.status||'unknown')}</span>${c.category?`<span class="claim-cat">${esc(c.category)}</span>`:''}</div><h3 class="claim-title">${esc(cleanClaimLabel(c.claim))}</h3>${reviewStatusBadge(c)}${metaParts?`<p class="claim-meta small">${metaParts}</p>`:''}<div class="meters">${meter('Evidence',c.evidenceScore)}${meter('Test',c.testability)}${meter('Survive',c.survivability)}</div><div class="claim-votes">${votes}</div>${actions?`<div class="actions"><button class="primary claim-study-btn" onclick="selectClaim('${esc(c.id)}')">Study Claim →</button></div>`:''}</article>`}
const CLAIM_TYPE_HINTS={'Physical/Testable':'Factual statements about the physical world — scientific, empirical, or statistical. Best suited for this system.','Historical':'Claims about past events. Specify dates, actors, or documented outcomes where possible.','Religious/Belief':'Matters of faith or personal conviction. Difficult to falsify — evidence scores will reflect that.','Conspiracy':'Allegations of coordinated deception. Requires specific claims about who, what, and when — not just suspicion.','Product Claim':'Marketing or performance assertions about a specific product or service.','Medical/High Risk':'Health-related claims. Will be flagged for high scrutiny. Be specific and cite sources if you have them.'};
const CAT_CHIPS=['Medicine','Science','Politics','History','Religion','Economics','Law','Technology'];
function updateClaimTypeHint(){const t=document.getElementById('cType')?.value||'Physical/Testable';const el=document.getElementById('cTypeHint');if(el)el.textContent=CLAIM_TYPE_HINTS[t]||'';}
function setCatChip(cat){const el=document.getElementById('cCategory');if(el)el.value=cat;document.querySelectorAll('.cat-chip').forEach(b=>b.classList.toggle('cat-chip-active',b.dataset.cat===cat));}
function renderSubmit(){document.body.classList.remove('study-mode');document.getElementById('casefile').innerHTML=helperText();document.getElementById('side-tools').style.display='none';document.getElementById('main').innerHTML=`<div class="panel form-panel"><h2>Submit Claim</h2><p class="small">A claim is a single precise, testable public statement. State it as specifically as you can — evidence and pressure will be attached after submission. Pseudonymous by default.</p><details class="claim-guide"><summary>Writing tips</summary><div class="claim-guide-body"><div class="claim-guide-col"><p class="claim-guide-label claim-guide-good">✓ Good claims</p><ul class="claim-guide-list"><li>Names a specific quantity, date, or outcome</li><li>Could be proven false by evidence</li><li>About one specific thing</li><li><em>"The MMR vaccine does not cause autism — 2019 meta-analysis of 1.2M children"</em></li></ul></div><div class="claim-guide-col"><p class="claim-guide-label claim-guide-bad">✗ Avoid</p><ul class="claim-guide-list"><li>Opinions: <em>"vaccines are dangerous"</em></li><li>Slogans: <em>"politicians always lie"</em></li><li>Vague scope: <em>"the media is biased"</em></li><li>Unfalsifiable: <em>"5G causes harm"</em></li></ul></div></div></details><div class="hx-form"><input id="cClaim" placeholder="One precise, testable statement"><p class="small hx-form-field-hint">Category</p><div class="cat-chips">${CAT_CHIPS.map(c=>`<button type="button" class="cat-chip" data-cat="${c}" onclick="setCatChip('${c}')">${c}</button>`).join('')}</div><input id="cCategory" placeholder="Or type a category"><p class="small hx-form-field-hint">Claim type</p><select id="cType" onchange="updateClaimTypeHint()"><option>Physical/Testable</option><option>Historical</option><option>Religious/Belief</option><option>Conspiracy</option><option>Product Claim</option><option>Medical/High Risk</option></select><p class="small hx-form-field-hint" id="cTypeHint">${CLAIM_TYPE_HINTS['Physical/Testable']}</p><textarea id="cEvidence" placeholder="Your reason or initial evidence (optional)"></textarea><button class="primary" onclick="saveClaim()">Submit for Review</button><p class="small review-first-note">Enters admin Review before going public. Not visible until approved.</p></div></div>`}
function groupEvidenceByCllaim(items){const groups=new Map();for(const e of items){const key=e.claimId||e.claim_id||null;if(!groups.has(key))groups.set(key,{claimId:key,claim:e.claim||null,items:[]});groups.get(key).items.push(e);}return[...groups.values()].sort((a,b)=>{if(!a.claimId&&b.claimId)return 1;if(a.claimId&&!b.claimId)return -1;return(a.claim||'').localeCompare(b.claim||'');});}
function vaultGroupsHtml(items){if(!items.length)return'';const groups=groupEvidenceByCllaim(items);return groups.map(g=>{const sup=g.items.filter(e=>(e.stance||'support')==='support').length;const prs=g.items.filter(e=>{const s=e.stance||'support';return s==='pressure'||s==='attack';}).length;const counts=[sup>0?`${sup} support`:'',prs>0?`${prs} pressure`:''].filter(Boolean).join(' · ');const title=g.claim?cleanClaimLabel(g.claim):'Unlinked evidence';const isUnlinked=!g.claimId;return`<div class="vault-group${isUnlinked?' vault-group-unlinked':''}"><div class="vault-group-head"><span class="vault-group-title">${esc(title)}</span><div class="vault-group-meta"><span class="badge b-blue">${g.items.length} item${g.items.length===1?'':'s'}</span>${counts?`<span class="vault-group-counts">${esc(counts)}</span>`:''} ${g.claimId?`<button class="btn-link-small" onclick="studyFromVault('${esc(g.claimId)}')">Study claim ↗</button>`:''}</div></div><div class="vault-group-grid">${g.items.map(evidenceCard).join('')}</div></div>`;}).join('');}
async function renderVault(){document.body.classList.remove('study-mode');document.getElementById('casefile').innerHTML=helperText();document.getElementById('side-tools').style.display='none';document.getElementById('main').innerHTML='<div class="panel"><h2>Loading Evidence…</h2></div>';try{await loadEvidenceVault();document.getElementById('casefile').innerHTML=helperText();const count=evidenceVault.length;document.getElementById('main').innerHTML=`<div id="attach-modal" class="attach-modal" style="display:none"></div><div class="vault-header"><div class="vault-header-top"><h2>Evidence Vault</h2><span class="badge b-blue">${count} item${count===1?'':'s'}</span></div><p class="small">Reusable sources, documents, data, and records. Each item can be attached to multiple claims as support or as a pressure attack. Evidence records reflect what has been submitted — not an automatic verdict on the claim.</p>${graphBox()}</div><div class="vault-groups">${vaultGroupsHtml(evidenceVault)||'<div class="empty-state"><p>No evidence records yet.</p><p class="small">Open a claim from the <b>Claims</b> tab, enter Study mode, and use the side panel to add a source or pressure attack. Items saved there appear here and can be reused across multiple claims.</p><div class="actions" style="margin-top:8px"><button class="primary" onclick="setMode(\'arena\')">Browse Claims</button></div></div>'}</div>`}catch(e){renderError(e)}}
function evidenceCard(e){const a=parseAnalysis(e.body);const stance=e.linked_stance||e.stance||'support';const isPressure=stance==='pressure'||stance==='attack';const stanceClr=isPressure?'b-red':stance==='support'?'b-green':'b-yellow';const stanceMod=isPressure?'evidence-card-pressure':stance==='support'?'evidence-card-support':'evidence-card-neutral';const quality=e.quality||'unknown';const qualClr=quality==='repeatable'||quality==='documented'||quality==='media'?'b-blue':quality==='vibes'?'':'b-yellow';const mediaType=e.media_type||e.mediaType||'text';const reliability=e.reliability_score||e.reliabilityScore||null;const date=e.updated_at||e.updatedAt||e.created_at||e.createdAt||null;const dateStr=date?new Date(date).toLocaleDateString():null;const reuse=e.reuse_count||e.reuseCount||null;const claimBlock=e.claim?`<div class="vault-card-claim"><span class="pill">linked claim</span><span class="small">${esc(cleanClaimLabel(e.claim))}</span><span class="badge ${cls(e.claimStatus)}">${esc(e.claimStatus||'unknown')}</span></div>`:'';return`<article class="card evidence-card ${stanceMod}"><div class="vault-card-head"><b class="vault-card-title">${esc(e.title)}</b><div class="vault-card-badges"><span class="badge ${stanceClr}">${esc(stance)}</span><span class="badge ${qualClr}">${a?'analysis':esc(quality)}</span><span class="badge">${esc(mediaType)}</span>${reliability?`<span class="pill">reliability ${esc(reliability)}</span>`:''} ${reuse&&reuse>1?`<span class="pill">↻ reused ${esc(reuse)}×</span>`:''}</div></div>${a?analysisSummary(a):evidenceBodyHtml(e.body||e.note||'',240)}${sourceLink(e.sourceUrl||e.source_url)}${claimBlock}${dateStr?`<p class="small vault-card-date">Updated ${esc(dateStr)}</p>`:''}<div class="actions">${(e.claimId||e.claim_id)?`<button onclick="studyFromVault('${esc(e.claimId||e.claim_id)}')" title="Open the linked claim in Study mode">Study Linked Claim</button>`:''}<button class="primary" onclick="attachEvidencePrompt('${esc(e.id)}')" title="Attach this item to a different claim as support or pressure">Attach to Claim</button></div></article>`}
function analysisSummary(a){return`<div class="analysis-card"><span class="badge ${cls(a.verdict)}">${esc(a.verdict||'analysis')}</span><div class="meters">${meter('Evidence',a.evidence_score||a.evidenceScore||0)}${meter('Test',a.testability||0)}${meter('Survive',a.survivability||0)}</div><p class="small">${esc(a.plain_language_summary||a.plainLanguageSummary||'Legacy analysis result stored in evidence. New results should be saved in Analysis.')}</p></div>`}
async function renderTruths(){document.body.classList.remove('study-mode');document.getElementById('casefile').innerHTML=helperText();document.getElementById('side-tools').style.display='none';document.getElementById('main').innerHTML='<div class="panel"><h2>Loading Truths…</h2></div>';try{await loadTruths();document.getElementById('casefile').innerHTML=helperText();document.getElementById('main').innerHTML=`<div class="section-head"><h2>Truths</h2><span class="badge b-yellow">widely asserted · not auto-verified</span>${graphBox()}</div><p class="small" style="margin:0 0 10px">Statements that circulate as fact — slogans, doctrines, inherited certainties, repeated beliefs. Recording a truth here does not verify it. Use <b>Send to Claim Review</b> to convert one into a pressure-testable public claim.</p><div class="panel compact-form hx-form"><h3 class="hx-form-head">Add a Truth</h3><input id="truthStatement" placeholder="Repeated statement or widely-asserted belief"><input id="truthCategory" placeholder="Category (e.g. Health, Religion, Politics)"><input id="truthOrigin" placeholder="Origin (e.g. family, media, scripture, science)"><p class="small hx-form-field-hint">Truth type</p><select id="truthType"><option value="common">Common truth</option><option value="religious">Religious truth</option><option value="political">Political truth</option><option value="scientific">Scientific consensus</option><option value="family">Family truth</option><option value="cultural">Cultural truth</option></select><button class="primary" onclick="submitTruth()">Submit Truth for Review</button><p class="small review-first-note">Enters Review before going public.</p></div><div class="grid truth-grid">${truths.map(t=>truthCard(t)).join('')||'<div class="panel"><div class="empty-state"><p>No truths match this view.</p><p class="small">Use the form above to record a statement that circulates as fact — a slogan, doctrine, or inherited certainty. These are not automatically verified.</p></div></div>'}</div>`}catch(e){renderError(e)}}
function truthCard(t){const metaParts=[t.category||'general',t.origin&&t.origin!=='unknown'?'origin: '+t.origin:null,'by '+(t.handle||'anon')].filter(Boolean).map(esc).join(' · ');const pressureStat=(t.pressureScore||0)>0?`<span class="truth-stat truth-stat-pressure" title="Pressure score">⊘ ${esc(t.pressureScore)} pressure</span>`:'';return`<article class="card truth-card"><div class="truth-card-head"><span class="badge b-yellow">${esc(t.truthType||'truth')}</span>${t.confidenceLabel?`<span class="badge">${esc(t.confidenceLabel)}</span>`:''} ${t.linkedClaimId?`<span class="badge b-green truth-linked-chip">→ claim exists</span>`:''}</div><h3 class="truth-title">${esc(cleanClaimLabel(t.statement))}</h3>${reviewStatusBadge(t)}<p class="small truth-meta">${metaParts}</p><div class="truth-stats"><span class="truth-stat" title="Reinforcement count">↻ ${esc(t.repetitionScore||1)} repeated</span>${pressureStat}</div><div class="actions"><button class="primary" onclick="convertTruth('${esc(t.id)}')" title="Creates a public, pressure-testable claim. Enters moderation before going public.">Send to Claim Review →</button></div></article>`}
async function renderReview(){document.body.classList.remove('study-mode');document.getElementById('casefile').innerHTML=helperText();document.getElementById('side-tools').style.display='none';const token=adminToken();document.getElementById('main').innerHTML=`<div class="review-page"><div class="review-header review-admin-bar"><div class="review-header-left"><h2>Review Queue</h2><span class="badge b-red">admin only</span></div><div class="review-token-form"><input id="adminToken" placeholder="Admin token" value="${esc(token)}" autocomplete="off"><button class="primary" onclick="saveAdminTokenAndLoadReview()">Load Queue</button><button onclick="clearAdminToken()">Clear Token</button></div></div><div id="reviewList" class="grid"><div class="panel">${token?'Loading review queue…':'Enter admin token to load the queue.'}</div></div></div>`;if(token){try{await loadReviewQueue();renderReviewList()}catch(e){document.getElementById('reviewList').innerHTML=`<div class="panel"><h3>Review unavailable</h3><p class="small">${esc(e.message||e)}</p></div>`}}}
function applyReviewFilter(list){const f=reviewStateFilter||'review';if(f==='all')return list;if(f==='reported')return list.filter(i=>(i.report_count||i.reportCount||0)>0);return list.filter(i=>(i.review_state||i.reviewState||'review')===f)}
function renderReviewFilterBar(list){const s=i=>(i.review_state||i.reviewState||'review');const counts={review:list.filter(i=>s(i)==='review').length,public:list.filter(i=>s(i)==='public').length,rejected:list.filter(i=>s(i)==='rejected').length,reported:list.filter(i=>(i.report_count||i.reportCount||0)>0).length,all:list.length};const defs=[['review','Pending'],['public','Public'],['rejected','Rejected'],['reported','Reported'],['all','All']];const chips=defs.map(([f,label])=>{const n=counts[f];const active=reviewStateFilter===f;return`<button class="review-filter-chip${active?' review-filter-chip-active':''}" onclick="setReviewFilter('${f}')">${label}${n>0?` <span class="review-filter-count">${n}</span>`:''}</button>`}).join('');const help=reviewFilterHelpText(reviewStateFilter);const rejectedCount=counts.rejected||0;const showCleanupHint=(rejectedCount>0||(reviewQueue.archived_total||0)>0)&&adminToken();const cleanupHint=showCleanupHint?`<p class="review-cleanup-hint">Cleanup: open <b>Rejected</b> → Inspect a smoke/test artefact → <b>Archive test artefact</b>.</p>`:'';return`<div class="review-filter-bar" style="grid-column:1/-1"><div class="review-filter-chips">${chips}</div>${help?`<p class="review-filter-help">${esc(help)}</p>`:''}${cleanupHint}</div>`}
function setReviewFilter(f){reviewStateFilter=f||'review';renderReviewList()}
function renderReviewList(){const all=reviewQueue.review||[];const list=applyReviewFilter(all);if(inspectedReviewItem&&!list.find(i=>i.id===inspectedReviewItem.id))inspectedReviewItem=null;if(pendingRejectReviewId&&!list.find(i=>i.id===pendingRejectReviewId))pendingRejectReviewId=null;if(pendingCleanupReviewId&&!list.find(i=>i.id===pendingCleanupReviewId))pendingCleanupReviewId=null;const bar=renderReviewFilterBar(all);const audit=renderReviewAuditSummary(all);const panel=inspectedReviewItem?renderReviewInspectPanel(inspectedReviewItem):'';const empty=`<div class="panel review-empty-state" style="grid-column:1/-1">${reviewEmptyText(reviewStateFilter)}</div>`;document.getElementById('reviewList').innerHTML=bar+audit+panel+(list.map(reviewCard).join('')||empty)}
function reviewCard(item){const type=item.target_type||item.targetType||item.type||'claim';const isTruth=type==='truth';const id=item.id;const title=isTruth?(item.statement||'Truth'):(item.claim||'Claim');const state=item.review_state||item.reviewState||'review';const stateClr=state==='public'?'b-green':state==='rejected'?'b-red':'b-yellow';const cardMod=state==='public'?'review-card-public':state==='rejected'?'review-card-rejected':state==='duplicate'?'review-card-duplicate':'review-card-pending';const isSelected=!!(inspectedReviewItem&&inspectedReviewItem.id===id);const isPendingReject=pendingRejectReviewId===id;const reports=item.report_count||item.reportCount||0;const scoreHint=isTruth?`rep ×${item.repetition_score||1}`:`score ${item.evidence_score||0}`;const metaParts=[item.category||'general',isTruth?(item.origin||null):(item.status||null),scoreHint].filter(Boolean);const updated=new Date(item.updated_at||item.updatedAt||item.created_at||Date.now()).toLocaleDateString();const rejectBtn=isPendingReject?`<span class="review-reject-confirm-msg">Reject? It will not become public.</span><button class="btn-reject-confirm" onclick="reviewDecisionUI('${esc(type)}','${esc(id)}','rejected')">Confirm Reject</button><button class="btn-reject-cancel" onclick="cancelRejectReview()">Cancel</button>`:`<button class="btn-reject" title="Hide this item permanently" onclick="requestRejectReview('${esc(id)}')">Reject</button>`;return`<article class="card review-card ${cardMod}${isTruth?' review-card-truth':''}${isSelected?' review-card-selected':''}${isPendingReject?' review-card-reject-pending':''}"><div class="review-card-head"><span class="badge ${isTruth?'b-yellow':'b-blue'}">${esc(type)}</span><span class="badge ${stateClr}">${esc(state)}</span>${reports>0?`<span class="badge b-red">⚑ ${esc(reports)} report${reports===1?'':'s'}</span>`:''}</div>${item.latest_report_reason?`<p class="review-reason-tag">Reason: ${esc(item.latest_report_reason)}</p>`:''}<h3 class="review-card-title">${esc(cleanClaimLabel(title))}</h3><p class="small review-card-meta">${metaParts.map(esc).join(' · ')}</p><p class="small review-card-date">Updated ${esc(updated)}</p><div class="review-actions"><button class="btn-inspect${isSelected?' btn-inspect-active':''}" title="Inspect all available fields" onclick="inspectReviewItem('${esc(id)}')">${isSelected?'▲ Inspecting':'Inspect'}</button><button class="btn-approve" title="Approve and publish to all users" onclick="reviewDecisionUI('${esc(type)}','${esc(id)}','public')">Approve</button><button class="btn-keep" title="Leave in the pending queue for now" onclick="reviewDecisionUI('${esc(type)}','${esc(id)}','review')">Keep Pending</button>${rejectBtn}</div></article>`}
function inspectReviewItem(id){const item=(reviewQueue.review||[]).find(i=>i.id===id)||null;inspectedReviewItem=(inspectedReviewItem&&inspectedReviewItem.id===id)?null:item;renderReviewList()}
function requestRejectReview(id){pendingRejectReviewId=(pendingRejectReviewId===id)?null:id;renderReviewList()}
function cancelRejectReview(){pendingRejectReviewId=null;renderReviewList()}
function requestCleanupReview(id){pendingCleanupReviewId=(pendingCleanupReviewId===id)?null:id;renderReviewList()}
function cancelCleanupReview(){pendingCleanupReviewId=null;renderReviewList()}
async function reviewCleanupUI(targetType,targetId){const item=(reviewQueue.review||[]).find(i=>i.id===targetId);const raw=item?(item.statement||item.claim||targetId):'item';const label=String(raw).slice(0,48)+(String(raw).length>48?'…':'');try{await api('/api/review/cleanup',{method:'POST',headers:adminHeaders(),body:JSON.stringify({target_type:targetType,target_id:targetId})});pendingCleanupReviewId=null;inspectedReviewItem=null;toast('Archived rejected test artefact.');loadGraphStatus().catch(()=>{});await loadReviewQueue();renderReviewList()}catch(e){toast(e.message||'Archive failed.')}}
function reviewFilterHelpText(f){const t={review:'Items awaiting admin decision.',public:'Approved items visible to users.',rejected:'Hidden items kept for audit/history.',reported:'User-flagged items. Reports are signals, not proof.',all:'Everything returned by the review queue.'};return t[f||'review']||''}
function reviewEmptyText(f){const t={review:'<p class="small">No pending items.</p><p class="small review-first-note">New claim and truth submissions appear here before going public. Approve to make an item visible; reject to keep it private.</p>',public:'<p class="small">No approved items in this filter.</p><p class="small review-first-note">Approved items are visible to all users.</p>',rejected:'<p class="small">No rejected items.</p><p class="small review-first-note">Rejected items stay private. Use <b>Archive</b> on smoke/test artefacts to remove them from the active queue.</p>',reported:'<p class="small">No reported items.</p><p class="small review-first-note">User reports are signals, not proof. Review each item before deciding.</p>',all:'<p class="small">No Review items found.</p>'};return t[f||'review']||'<p class="small">No items found.</p>'}
function reviewStateLabel(item){const state=item.review_state||item.reviewState||'review';const labels={public:'Public — live and visible to all users',rejected:'Rejected — hidden from public, kept for audit',review:'Pending review — not yet public'};return labels[state]||`State: ${state}`}
function isSuspectedTestArtefact(item){const text=[item.claim||'',item.statement||'',item.origin||'',item.category||'',item.handle||''].join(' ').toLowerCase();return text.includes('smoke')||/\btest\b/.test(text)||text.includes('automated write')||text.includes('automated smoke')}
function renderReviewAuditSummary(items){if(!items.length)return'';const s=i=>i.review_state||i.reviewState||'review';const pending=items.filter(i=>s(i)==='review').length;const pub=items.filter(i=>s(i)==='public').length;const rejected=items.filter(i=>s(i)==='rejected').length;const reported=items.filter(i=>(i.report_count||i.reportCount||0)>0).length;const smoke=items.filter(isSuspectedTestArtefact).length;const dupes=items.filter(i=>!!(i.duplicate_of||i.duplicateOf||(s(i)==='duplicate'))).length;const stats=[{label:'Total',n:items.length,cls:''},{label:'Pending',n:pending,cls:'yellow'},{label:'Public',n:pub,cls:'green'},{label:'Rejected',n:rejected,cls:'red'},{label:'Reported',n:reported,cls:'red'},{label:'~Smoke/Test',n:smoke,cls:'smoke'},{label:'Duplicates',n:dupes,cls:''}];const statsHtml=stats.map(({label,n,cls})=>`<div class="review-audit-stat${cls?' review-audit-stat-'+cls:''}"><span class="review-audit-n">${n}</span><span class="review-audit-label">${label}</span></div>`).join('');const archivedTotal=reviewQueue.archived_total||0;const archivedClaims=reviewQueue.archived_claims||0;const archivedTruths=reviewQueue.archived_truths||0;const archivedHtml=reviewAuditOpen&&archivedTotal>0?`<div class="review-audit-archived"><span class="review-audit-archived-label">Archived (not in active queue)</span><div class="review-audit-archived-stats"><div class="review-audit-stat review-audit-stat-archived"><span class="review-audit-n">${archivedTotal}</span><span class="review-audit-label">Total archived</span></div>${archivedClaims>0?`<div class="review-audit-stat review-audit-stat-archived"><span class="review-audit-n">${archivedClaims}</span><span class="review-audit-label">Claims</span></div>`:''} ${archivedTruths>0?`<div class="review-audit-stat review-audit-stat-archived"><span class="review-audit-n">${archivedTruths}</span><span class="review-audit-label">Truths</span></div>`:''}</div><p class="review-audit-note review-audit-archived-note">Archived items are smoke/test artefacts removed from the queue. They remain in the database for audit.</p></div>`:'';const body=reviewAuditOpen?`<div class="review-audit-body"><div class="review-audit-stats">${statsHtml}</div>${archivedHtml}<p class="review-audit-note">Audit only — no cleanup action is performed from this summary.</p></div>`:'';return`<div class="review-audit-bar" style="grid-column:1/-1"><div class="review-audit-header"><button class="review-audit-toggle" onclick="toggleReviewAudit()">${reviewAuditOpen?'▾':'▸'} Audit Summary</button>${reviewAuditOpen?`<span class="review-audit-total">${items.length} total in loaded queue</span>`:''}</div>${body}</div>`}
function toggleReviewAudit(){reviewAuditOpen=!reviewAuditOpen;renderReviewList()}
function renderReviewInspectPanel(item){const type=item.target_type||item.targetType||item.type||'claim';const isTruth=type==='truth';const id=item.id;const title=isTruth?(item.statement||'—'):(item.claim||'—');const state=item.review_state||item.reviewState||'review';const stateClr=state==='public'?'b-green':state==='rejected'?'b-red':'b-yellow';const reports=item.report_count||item.reportCount||0;const fields=[];fields.push(['ID',`<code class="review-inspect-id">${esc(id)}</code>`]);fields.push(['Type',`<span class="badge ${isTruth?'b-yellow':'b-blue'}">${esc(type)}</span>`]);fields.push(['State',`<span class="badge ${stateClr}">${esc(state)}</span>`]);if(reports>0)fields.push(['Reports',`<span class="badge b-red">⚑ ${reports} report${reports===1?'':'s'}</span>`]);if(item.latest_report_reason)fields.push(['Report Reason',`<span class="review-reason-tag">${esc(item.latest_report_reason)}</span>`]);if(isTruth){if(item.truth_type||item.truthType)fields.push(['Truth Type',esc(item.truth_type||item.truthType)]);if(item.category)fields.push(['Category',esc(item.category)]);if(item.origin)fields.push(['Origin',esc(item.origin)]);if(item.confidence_label||item.confidenceLabel)fields.push(['Confidence',esc(item.confidence_label||item.confidenceLabel)]);const rep=item.repetition_score??item.repetitionScore??null;if(rep!=null)fields.push(['Repetitions',esc(rep)]);const ps=item.pressure_score??item.pressureScore??null;if(ps!=null)fields.push(['Pressure Score',esc(ps)]);const cc=item.converted_claim_count??item.convertedClaimCount??null;if(cc!=null)fields.push(['Converted Claims',esc(cc)]);const linked=item.linked_claim_id||item.linkedClaimId||null;if(linked)fields.push(['Linked Claim',`<button class="btn-link-small" onclick="openReviewClaimStudy('${esc(linked)}')">${esc(linked)} ↗</button>`]);}else{if(item.status)fields.push(['Status',esc(item.status)]);if(item.category)fields.push(['Category',esc(item.category)]);if(item.type)fields.push(['Claim Type',esc(item.type)]);if(item.handle)fields.push(['Submitted By',esc(item.handle)]);const es=item.evidence_score??item.evidenceScore??null;if(es!=null)fields.push(['Evidence',`${esc(es)}/100`]);const ts=item.testability??null;if(ts!=null)fields.push(['Testability',`${esc(ts)}/100`]);const sv=item.survivability??null;if(sv!=null)fields.push(['Survivability',`${esc(sv)}/100`]);const contra=item.contradictions??0;if(contra>0)fields.push(['Pressure Points',esc(contra)]);if(item.damage)fields.push(['Damage',esc(item.damage)]);const dup=item.duplicate_of||item.duplicateOf||null;if(dup)fields.push(['Duplicate Of',esc(dup)]);}const created=item.created_at||item.createdAt||null;if(created)fields.push(['Created',new Date(created).toLocaleString()]);const updated=item.updated_at||item.updatedAt||null;if(updated)fields.push(['Updated',new Date(updated).toLocaleString()]);const fieldsHtml=fields.map(([k,v])=>`<div class="review-inspect-field"><span class="review-inspect-label">${k}</span><span class="review-inspect-val">${v}</span></div>`).join('');const studyBtn=!isTruth?`<button class="primary btn-study-review" onclick="openReviewClaimStudy('${esc(id)}')">Open Study View ↗</button>`:isTruth&&(item.linked_claim_id||item.linkedClaimId)?`<button class="btn-study-review" onclick="openReviewClaimStudy('${esc(item.linked_claim_id||item.linkedClaimId)}')">Study Linked Claim ↗</button>`:'';const isPendingReject=pendingRejectReviewId===id;const rejectSection=isPendingReject?`<span class="review-reject-confirm-msg">Reject? It will not become public.</span><button class="btn-reject-confirm" onclick="reviewDecisionUI('${esc(type)}','${esc(id)}','rejected')">Confirm Reject</button><button class="btn-reject-cancel" onclick="cancelRejectReview()">Cancel</button>`:`<button class="review-inspect-reject" onclick="requestRejectReview('${esc(id)}')">Reject</button>`;const stateDotCls=state==='public'?'review-state-dot-public':state==='rejected'?'review-state-dot-rejected':'review-state-dot-pending';const stateText=reviewStateLabel(item);const reportsBadge=reports>0?` <span class="badge b-red">⚑ ${reports} report${reports===1?'':'s'}</span>`:'';const isPendingCleanup=pendingCleanupReviewId===id;const isArtefact=state==='rejected'&&isSuspectedTestArtefact(item);const cleanupSection=isArtefact?(isPendingCleanup?`<span class="review-reject-confirm-msg">Archive this test artefact?</span><button class="btn-reject-confirm" onclick="reviewCleanupUI('${esc(type)}','${esc(id)}')">Confirm Archive</button><button class="btn-reject-cancel" onclick="cancelCleanupReview()">Cancel</button>`:`<button class="review-inspect-cleanup" onclick="requestCleanupReview('${esc(id)}')">Archive test artefact</button>`):'';return`<div class="review-inspect-panel" style="grid-column:1/-1"><div class="review-inspect-header"><div class="review-inspect-title-row"><span class="badge ${isTruth?'b-yellow':'b-blue'}">${esc(type)}</span><h3 class="review-inspect-title">${esc(cleanClaimLabel(title))}</h3></div><button class="btn-close-inspect" onclick="inspectReviewItem('${esc(id)}')" title="Close panel">✕ Close</button></div><div class="review-inspect-state-bar"><span class="review-state-dot ${stateDotCls}"></span><span class="review-inspect-state-label">${esc(stateText)}</span>${reportsBadge}</div><div class="review-inspect-fields">${fieldsHtml||'<p class="small">Only preview data available for this item.</p>'}</div><div class="review-inspect-actions"><button class="btn-approve review-inspect-approve" onclick="reviewDecisionUI('${esc(type)}','${esc(id)}','public')">Approve</button><button class="btn-keep" onclick="reviewDecisionUI('${esc(type)}','${esc(id)}','review')">Keep Pending</button>${rejectSection}${cleanupSection}${studyBtn}</div></div>`}
async function openReviewClaimStudy(id){mode='arena';document.querySelectorAll('.tab').forEach(x=>x.classList.remove('active'));document.getElementById('tab-arena')?.classList.add('active');await selectClaim(id)}
function studyFromVault(id){mode='arena';document.querySelectorAll('.tab').forEach(x=>x.classList.remove('active'));document.getElementById('tab-arena')?.classList.add('active');selectClaim(id)}
async function saveAdminTokenAndLoadReview(){const token=document.getElementById('adminToken')?.value||'';localStorage.setItem(LS_ADMIN,token);await renderReview()}
function clearAdminToken(){localStorage.removeItem(LS_ADMIN);reviewQueue={claims:[],truths:[],review:[]};inspectedReviewItem=null;pendingRejectReviewId=null;renderReview()}
async function reviewDecisionUI(targetType,targetId,decision){const item=(reviewQueue.review||[]).find(i=>i.id===targetId);const raw=item?(item.statement||item.claim||targetId):'item';const label=String(raw).slice(0,48)+(String(raw).length>48?'…':'');const msgs={public:`Approved. Item is now public.`,rejected:`Rejected. Item will not be public.`,review:`Kept in Review. Item is not yet public.`};try{await api('/api/review/decision',{method:'POST',headers:adminHeaders(),body:JSON.stringify({targetType,targetId,decision})});pendingRejectReviewId=null;toast(msgs[decision]||`Review set to ${decision}`);loadGraphStatus().catch(()=>{});await loadReviewQueue();renderReviewList()}catch(e){toast(e.message||'Review action failed')}}
async function attachEvidencePrompt(evidenceId){if(!claims.length)await loadClaims(false);if(!claims.length)return toast('No claims available to attach to.');attachingEvidenceId=evidenceId;const modal=document.getElementById('attach-modal');if(!modal)return;const opts=claims.map((c,i)=>`<option value="${i}">${esc(cleanClaimLabel(c.claim))}</option>`).join('');modal.innerHTML=`<div class="attach-modal-inner"><h3>Attach to Claim</h3><p class="small">Choose a claim and how this evidence should be attached.</p><select id="attach-claim-select" style="margin-bottom:2px">${opts}</select><div class="attach-stance-row"><button class="btn-approve" onclick="doAttachEvidence('support')">Attach as Support</button><button class="btn-reject" onclick="doAttachEvidence('pressure')">Attach as Pressure</button><button class="btn-keep" onclick="closeAttachModal()">Cancel</button></div></div>`;modal.style.display='flex';}
async function doAttachEvidence(stance){const select=document.getElementById('attach-claim-select');if(!select)return;const target=claims[Number(select.value)];if(!target)return toast('Invalid claim selection');const id=attachingEvidenceId;closeAttachModal();try{await api('/api/evidence-attach',{method:'POST',body:JSON.stringify({evidenceId:id,claimId:target.id,stance})});await loadGraphStatus();toast(`Evidence attached as ${stance}`);if(mode==='vault')await renderVault()}catch(e){toast(e.message||'Could not attach evidence')}}
function closeAttachModal(){const modal=document.getElementById('attach-modal');if(modal)modal.style.display='none';attachingEvidenceId=null;}
async function submitTruth(){const statement=document.getElementById('truthStatement')?.value||'';const category=document.getElementById('truthCategory')?.value||'general';const origin=document.getElementById('truthOrigin')?.value||'unknown';const truthType=document.getElementById('truthType')?.value||'common';try{await api('/api/truths',{method:'POST',body:JSON.stringify({statement,category,origin,truthType})});await loadGraphStatus();toast('Truth submitted for Review. It will appear publicly after approval.');await renderTruths()}catch(e){toast(e.message||'Truth submission failed.')}}
function runPackSummary(){if(!selected)return'';const ev=(selected.evidence||[]).length;const pr=(selected.pressure||[]).length;const ts=(selected.tests||[]).length;const an=(selected.analyses||[]).length;let statusLabel,statusCls,statusHint;if(!lastPacket){statusLabel='Not built';statusCls='rp-status-idle';statusHint='Click Build RunPack to generate the packet.';}else if(lastPacketClaimId&&lastPacketClaimId!==selected.id){statusLabel='Built for different claim';statusCls='rp-status-warn';statusHint='This packet was built for a different claim. Rebuild to update.';}else if(lastPacketIsFallback){statusLabel='Fallback packet';statusCls='rp-status-warn';statusHint='Generated locally — backend evidence and lineage may be incomplete.';}else{statusLabel='Ready';statusCls='rp-status-ready';statusHint='Packet built. Copy or download below.';}return`<div class="rp-summary"><div class="rp-summary-row"><span class="rp-summary-count" title="Support evidence items"><b>${ev}</b> evidence</span><span class="rp-summary-count" title="Pressure / attack items"><b>${pr}</b> pressure</span><span class="rp-summary-count" title="Testable methods"><b>${ts}</b> tests</span><span class="rp-summary-count" title="Saved AI analyses"><b>${an}</b> analyses</span></div><div class="rp-summary-status"><span class="rp-status-chip ${statusCls}">${esc(statusLabel)}</span><span class="small rp-status-hint">${esc(statusHint)}</span></div></div>`;}
function renderExport(){document.body.classList.remove('study-mode');document.getElementById('casefile').innerHTML=helperText();document.getElementById('side-tools').style.display='none';const claimCtx=selected?`<div class="runpack-claim-ctx"><span class="pill">claim to export</span><p class="runpack-claim-name">${esc(cleanClaimLabel(selected.claim))}</p><span class="badge ${cls(selected.status)}">${esc(selected.status||'unknown')}</span></div>`:'';const noClaimState=!selected?`<div class="empty-state runpack-no-claim-state"><p>No claim selected.</p><p class="small">Open a claim from the <b>Claims</b> tab → enter Study mode → click <b>Build RunPack</b>. Then return here to copy or download the packet.</p><div class="actions" style="margin-top:8px"><button class="primary" onclick="setMode('arena')">Browse Claims</button></div></div>`:'';const summary=runPackSummary();const outputBlock=lastPacket?`${lastPacketIsFallback?'<p class="small runpack-fallback-warn">⚠ Fallback RunPack — generated locally from cached data. Backend evidence and lineage may be incomplete.</p>':''}<p class="small rp-json-label">RunPack JSON — paste into any AI for pressure-testing and analysis</p><pre class="output runpack-export-output">${esc(lastPacket)}</pre>`:(selected?'<p class="small runpack-ready-hint">Click <b>Build RunPack</b> above to generate the export packet for this claim.</p>':'');document.getElementById('main').innerHTML=`<div class="panel"><h2>RunPack Export</h2><p class="small">A RunPack is a portable, AI-agnostic packet containing a claim, its evidence, pressure, tests, and analyses. No owner API credits are used.</p><p class="small review-first-note">Exporting does not make anything public — visibility still depends on admin Review approval.</p>${claimCtx}${summary}${noClaimState}<div class="runpack-actions"><button class="primary" onclick="generateRunPack()">${lastPacket&&lastPacketClaimId===selected?.id?'Rebuild RunPack':'Build RunPack'}</button><button onclick="copyAIP()" title="Copy the packet to clipboard (generates first if needed)">Copy RunPack</button><button onclick="downloadRunPack()" title="Download the packet as a JSON file">Download RunPack JSON</button></div><details class="runpack-visible-data-toggle"><summary>Download all visible data</summary><p class="small">Exports everything currently visible in your session — claims, evidence, truths, belief snapshots, graph status. Not the same as a RunPack.</p><div class="actions"><button onclick="downloadJSON()">Download all visible data JSON</button></div></details>${outputBlock}</div>`}
async function selectClaim(id){try{const data=await api('/api/claims/'+id);selected=data.claim;selected.claim=cleanClaimLabel(selected.claim);selected.evidence=data.evidence||[];selected.pressure=data.pressure||[];selected.tests=data.tests||data.home_tests||[];selected.analyses=data.analyses||[];selected.lineage=data.lineage||null;renderStudy();toast('Study loaded')}catch(e){const fallback=claims.find(c=>c.id===id)||selected;if(fallback){selected=fallback;selected.analyses=selected.analyses||[];selected.lineage=selected.lineage||null;renderStudy()}toast(e.message||'Could not load claim')}}
function reviewStatusBadge(c,withNote=false){const rs=c.review_state||c.reviewState||c.visibility||'';const reports=c.report_count||c.reportCount||0;let label='',clr='';if(reports>0){label='Reported';clr='b-red';}else if(rs==='public'||rs==='approved'||rs==='live'){label='Public';clr='b-green';}else if(rs==='rejected'){label='Rejected';clr='b-red';}else if(rs==='archived'){label='Archived';clr='b-yellow';}else if(rs==='review'||rs==='pending'||rs==='queued'){label='Pending Review';clr='b-yellow';}if(!label)return'';if(!withNote)return`<div class="review-badge-block"><span class="badge ${clr}">${label}</span></div>`;const note=rs==='rejected'?'<p class="small study-review-note">This claim is kept out of public view.</p>':label==='Pending Review'?'<p class="small study-review-note">This claim is not public until approved.</p>':'';return`<div class="study-review-state"><span class="badge ${clr}">${label}</span>${note}</div>`}
function studyReviewBadge(c){return reviewStatusBadge(c,true)}
function renderStudy(){if(!selected)return;document.body.classList.add('study-mode');document.getElementById('side-tools').style.display='block';const studyMeta=[selected.category,selected.type,selected.handle?'by '+selected.handle:''].filter(Boolean).map(esc).join(' · ');document.getElementById('main').innerHTML=`<div class="study"><div class="study-header"><div class="study-nav"><button onclick="backToArena()">← Back</button><span class="badge ${cls(selected.status)}">${esc(selected.status||'unknown')}</span></div><h2>${esc(cleanClaimLabel(selected.claim))}</h2>${studyReviewBadge(selected)}${studyMeta?`<p class="study-meta small">${studyMeta}</p>`:''}<div class="meters wide">${meter('Evidence',selected.evidenceScore)}${meter('Testability',selected.testability)}${meter('Survivability',selected.survivability)}</div><div class="study-vote-row"><div class="study-votes"><span class="study-vote-label">Vote</span><button class="vote yes" onclick="voteClaim('believe')">▲ Believe</button><button class="vote no" onclick="voteClaim('reject')">▼ Reject</button><button class="vote unsure" onclick="voteClaim('unsure')">~ Unsure</button></div><div class="study-actions"><button class="primary" onclick="generateRunPack()">Build RunPack</button></div></div></div>${sectionArgumentFlow()}${sectionLineage()}<div class="inv-board-head"><span>Investigation Board</span></div><div class="study-grid"><section class="panel evidence-panel">${sectionEvidence()}</section><section class="panel pressure-panel">${sectionPressure()}</section><section class="panel tests-panel">${sectionTests()}</section><section class="panel analysis-panel">${sectionAnalyses()}</section></div></div>`;renderCaseMini();patchEvidencePanel();patchRunPackPanel()}
function renderCaseMini(){const l=selected?.lineage||{};const ev=(l.evidenceLinks||[]).length;const pr=l.pressureCount||0;const ts=l.testCount||0;const an=l.analysisCount||0;const rs=selected.review_state||selected.reviewState||'';const rsLabel=rs==='public'?'Public':rs==='rejected'?'Rejected':rs==='review'||rs==='pending'||rs==='queued'?'Pending Review':'';const rsCls=rs==='public'?'b-green':rs==='rejected'?'b-red':'b-yellow';document.getElementById('casefile').innerHTML=`<p class="casefile-claim-name">${esc(cleanClaimLabel(selected.claim))}</p>${rsLabel?`<div class="casefile-badge-row"><span class="badge ${rsCls}">${rsLabel}</span></div>`:''}<div class="casefile-counts"><span title="Support evidence">${ev} evidence</span><span title="Pressure attacks">${pr} pressure</span><span title="Tests">${ts} tests</span><span title="Saved analysis">${an} analysis</span></div>`}
function evidenceMeta(e){const reused=e.link_type==='reused';const stance=e.linked_stance||e.stance||'support';const quality=e.quality||'';const parts=[reused?'reused':null,quality||null,stance].filter(Boolean);return parts.map(esc).join(' · ')}
function evidenceItem(e){const a=parseAnalysis(e.body||e.note);if(a)return`<div class="row analysis-card"><div class="inv-item-head"><b class="inv-item-title">${esc(e.title)}</b><span class="badge ${cls(a.verdict)}">${esc(a.verdict||'analysis')}</span><span class="pill">legacy</span></div><div class="meters">${meter('Evidence',a.evidence_score||0)}${meter('Test',a.testability||0)}${meter('Survive',a.survivability||0)}</div><p class="small">${esc(a.plain_language_summary||'Structured AIP/AI analysis stored in old evidence field.')}</p><details><summary>Support / pressure / missing tests</summary><h4>Support</h4>${listBits(a.strongest_support)}<h4>Pressure</h4>${listBits(a.strongest_pressure)}<h4>Missing tests</h4>${listBits(a.missing_tests)}</details></div>`;const reused=e.link_type==='reused';return`<div class="row${reused?' ev-row-reused':''}"><div class="inv-item-head"><b class="inv-item-title">${esc(e.title)}</b><span class="pill">${evidenceMeta(e)}</span></div>${evidenceBodyHtml(e.body||e.note,300)}${e.link_note?`<p class="small"><b>Reuse note:</b> ${esc(e.link_note)}</p>`:''}${sourceLink(e.source_url||e.sourceUrl)}</div>`}
function analysisItem(a){const raw=a.raw||a;const verdict=a.verdict||raw.verdict||'analysis';const summary=a.plainLanguageSummary||raw.plain_language_summary||'Stored analysis result.';const src=a.source||raw.source||'runpack-user';return`<div class="analysis-result-card"><div class="inv-item-head"><span class="badge ${cls(verdict)}">${esc(verdict)}</span><span class="pill">${esc(src)}</span></div><div class="meters">${meter('Evidence',a.evidenceScore||raw.evidence_score||0)}${meter('Test',a.testability||raw.testability||0)}${meter('Survive',a.survivability||raw.survivability||0)}</div><p class="small">${esc(summary)}</p><details class="analysis-details"><summary>Support · Pressure · Missing tests</summary><div class="analysis-detail-grid"><div><h4>Support</h4>${listBits(a.strongestSupport||raw.strongest_support)}</div><div><h4>Pressure</h4>${listBits(a.strongestPressure||raw.strongest_pressure)}</div><div><h4>Missing tests</h4>${listBits(a.missingTests||raw.missing_tests)}</div></div></details></div>`}
function sectionLineage(){const l=selected?.lineage||{};const truths=l.truths||[];const evidenceLinks=l.evidenceLinks||[];return`<section class="panel lineage-panel"><div class="section-head"><h3>Lineage</h3><span class="badge b-blue">upstream origin</span></div><div class="graph-status"><span><b>${esc((l.beliefs||[]).length)}</b><small>Beliefs</small></span><span><b>${esc(truths.length)}</b><small>Truths</small></span><span><b>1</b><small>Claim</small></span><span><b>${esc(evidenceLinks.length)}</b><small>Evidence</small></span><span><b>${esc(l.pressureCount||0)}</b><small>Pressure</small></span><span><b>${esc(l.testCount||0)}</b><small>Tests</small></span><span><b>${esc(l.analysisCount||0)}</b><small>Analysis</small></span></div>${truths.length?`<div class="row"><span class="pill">upstream truth</span>${truths.slice(0,3).map(t=>`<p class="small"><b>${esc(cleanClaimLabel(t.statement||'Truth'))}</b><br>${esc(t.bridge_note||t.origin||'Linked truth')}</p>`).join('')}</div>`:'<p class="small">No upstream truth linked yet. This claim may have been submitted directly or promoted from a belief without a formal truth bridge.</p>'}</section>`}
function firstEvidence(){return(selected.evidence||[]).find(e=>!parseAnalysis(e.body||e.note))}
function firstPressure(){return(selected.pressure||[])[0]}
function firstTest(){return(selected.tests||[])[0]}
function firstAnalysis(){return(selected.analyses||[])[0]}
function sectionArgumentFlow(){const e=firstEvidence(),p=firstPressure(),t=firstTest(),a=firstAnalysis();const raw=a?.raw||a||{};return`<section class="panel flow-panel"><div class="section-head"><h3>Claim Flow</h3><span class="badge b-green">read this first</span></div><div class="flow-steps"><div class="row"><span class="pill">1 · Why people think it is true</span><p class="small">${e?`<b>${esc(e.title||'Evidence')}</b><br>${esc(shortText(e.body||e.note,260))}`:'No support evidence attached yet — add one from the side panel.'}</p></div><div class="row"><span class="pill">2 · What attacks it</span><p class="small">${p?`<b>${esc(p.title||'Pressure')}</b><br>${esc(shortText(p.body||p.note,260))}`:'No pressure attached yet — add an objection from the side panel.'}</p></div><div class="row"><span class="pill">3 · How to test it</span><p class="small">${t?`<b>${esc(t.title||'Test')}</b><br>${esc(shortText(t.instructions,260))}`:'No test added yet — add one in the Tests section below.'}</p></div><div class="row"><span class="pill">4 · What analysis says</span><p class="small">${a?`<b>${esc(a.verdict||raw.verdict||'Analysis')}</b><br>${esc(shortText(a.plainLanguageSummary||raw.plain_language_summary||'Stored analysis result.',260))}`:'No analysis saved yet — generate a RunPack and paste the result below.'}</p></div></div></section>`}
function reusedItemCompact(e){return`<div class="reused-item-compact"><span class="inv-item-title">${esc(e.title)}</span><span class="pill">${evidenceMeta(e)}</span>${e.link_note?`<span class="reused-item-note">${esc(e.link_note)}</span>`:''} ${sourceLink(e.source_url||e.sourceUrl)}</div>`}
function reusedEvidenceHtml(reused){const subHead=`<div class="study-sub-head study-sub-reused">Reused from vault<span class="badge">${reused.length}</span></div>`;if(reused.length<=3)return subHead+reused.map(evidenceItem).join('');const groups=new Map();for(const e of reused){const key=e.claim_id||'unknown';if(!groups.has(key)){const src=(claims||[]).find(c=>c.id===key);groups.set(key,{claimId:key,claimText:src?.claim||null,items:[]});}groups.get(key).items.push(e);}const sorted=[...groups.values()].sort((a,b)=>b.items.length-a.items.length);const groupsHtml=sorted.map(g=>{const label=g.claimText?cleanClaimLabel(g.claimText):`claim ${g.claimId.slice(-6)}`;return`<details class="reused-source-group"><summary class="reused-source-head"><span class="reused-source-label">${esc(label)}</span><span class="badge">${g.items.length} item${g.items.length===1?'':'s'}</span></summary><div class="reused-source-items">${g.items.map(reusedItemCompact).join('')}</div></details>`;}).join('');if(reused.length>=10)return`<details class="reused-collapse-outer"><summary class="reused-collapse-head"><span class="study-sub-reused">Reused from vault</span><span class="badge">${reused.length} items</span><span class="reused-collapse-hint">· ${sorted.length} source claim${sorted.length===1?'':'s'} · click to expand</span></summary><div class="reused-collapse-body">${groupsHtml}</div></details>`;return subHead+groupsHtml;}
function sectionEvidence(){const ev=selected.evidence||[];const head=`<div class="inv-sec-head"><div class="inv-sec-title"><h3>Support Evidence</h3><span class="badge b-blue">${ev.length} item${ev.length===1?'':'s'}</span></div><p class="inv-sec-purpose">What currently supports this claim.</p></div>`;if(!ev.length)return head+'<div class="empty-state"><p>No supporting evidence yet.</p><p class="small">Use the side panel to add a source, document, or reuse an existing vault item.</p></div>';const analyses=ev.filter(e=>parseAnalysis(e.body||e.note));const direct=ev.filter(e=>!parseAnalysis(e.body||e.note)&&e.link_type!=='reused');const reused=ev.filter(e=>!parseAnalysis(e.body||e.note)&&e.link_type==='reused');const hasGroups=direct.length>0&&reused.length>0;if(!hasGroups){if(reused.length>0)return head+reusedEvidenceHtml(reused);return head+ev.map(evidenceItem).join('');}return head+analyses.map(evidenceItem).join('')+(direct.length?`<div class="study-sub-head">Direct evidence<span class="badge b-blue">${direct.length}</span></div>${direct.map(evidenceItem).join('')}`:'')+( reused.length?reusedEvidenceHtml(reused):'');}
function pressureItemHtml(p){const a=parseAnalysis(p.body||p.note);return a?`<div class="row analysis-card"><div class="inv-item-head"><b class="inv-item-title">${esc(p.title)}</b><span class="badge ${cls(a.verdict||'analysis')}">${esc(a.verdict||'analysis')}</span><span class="pill">legacy</span></div><p class="small">${esc(a.plain_language_summary||'Structured analysis pressure result.')}</p>${listBits(a.strongest_pressure)}</div>`:`<div class="row"><div class="inv-item-head"><b class="inv-item-title">${esc(p.title)}</b><span class="pill">severity ${esc(p.severity||1)}</span></div>${evidenceBodyHtml(p.body||p.note,300)}</div>`;}
function sectionPressure(){const pr=selected.pressure||[];const head=`<div class="inv-sec-head"><div class="inv-sec-title"><h3>Pressure / Attacks</h3><span class="badge b-yellow">${pr.length} item${pr.length===1?'':'s'}</span></div><p class="inv-sec-purpose">What challenges, contradicts, or weakens it.</p></div>`;if(!pr.length)return head+'<div class="empty-state"><p>No pressure or attacks yet.</p><p class="small">Use the side panel to add an objection, contradiction, or counter-evidence.</p></div>';const analyses=pr.filter(p=>parseAnalysis(p.body||p.note));const plain=pr.filter(p=>!parseAnalysis(p.body||p.note));const high=plain.filter(p=>(p.severity||1)>=3);const other=plain.filter(p=>(p.severity||1)<3);const hasGroups=high.length>0&&other.length>0;if(!hasGroups)return head+pr.map(pressureItemHtml).join('');return head+analyses.map(pressureItemHtml).join('')+(high.length?`<div class="study-sub-head study-sub-high">Significant pressure<span class="badge b-red">${high.length}</span></div>${high.map(pressureItemHtml).join('')}`:'')+( other.length?`<div class="study-sub-head">Other pressure<span class="badge">${other.length}</span></div>${other.map(pressureItemHtml).join('')}`:'');}
function sectionTests(){const ts=selected.tests||[];return`<div class="inv-sec-head"><div class="inv-sec-title"><h3>Tests</h3><span class="badge b-green">${ts.length} test${ts.length===1?'':'s'}</span></div><p class="inv-sec-purpose">Ways this claim could be checked or falsified.</p></div><div class="test-add-form"><input id="testTitle" placeholder="Test title"><textarea id="testInstructions" placeholder="Instructions: what to do, what to record, how to repeat it"></textarea><div class="test-form-row"><select id="testSafety"><option value="low">low safety risk</option><option value="medium">medium safety risk</option><option value="high">high safety risk</option></select><select id="testDifficulty"><option value="easy">easy</option><option value="medium">medium</option><option value="hard">hard</option></select></div><button class="primary" onclick="addHomeTestUI()">Add Test</button></div>${ts.map(t=>`<div class="test-item"><div class="inv-item-head"><b class="inv-item-title">${esc(t.title)}</b><span class="pill">${esc(t.difficulty||'test')} · ${esc(t.safety_level||t.safetyLevel||'normal')}</span></div><p class="small">${esc(t.instructions)}</p></div>`).join('')||'<div class="empty-state"><p>No tests yet.</p><p class="small">A test describes a real-world way this claim could be checked or falsified. Use the form above to add one.</p></div>'}`}
function sectionAnalyses(){const an=selected.analyses||[];return`<div class="inv-sec-head"><div class="inv-sec-title"><h3>Analysis</h3><span class="badge b-blue">${an.length} result${an.length===1?'':'s'}</span></div><p class="inv-sec-purpose">Saved RunPack or AI analysis results.</p></div><div class="analysis-save-form"><p class="small">Click <b>Build RunPack</b> in the claim header → paste into any AI → paste the JSON result here to save it.</p><textarea id="analysisPaste" placeholder="Paste RunPack output JSON here"></textarea><div class="actions"><button class="primary" onclick="saveAnalysisResult()">Save Analysis</button></div></div>${an.map(analysisItem).join('')||'<div class="empty-state"><p>No analysis saved yet.</p><p class="small">Build a RunPack above → paste it into any AI → paste the JSON result back here to save it against this claim.</p></div>'}`}
function backToArena(){document.body.classList.remove('study-mode');selected=null;setMode('arena')}
async function voteClaim(vote){if(!selected)return toast('Select a claim first');try{const data=await api('/api/claim-vote',{method:'POST',body:JSON.stringify({claimId:selected.id,vote})});selected=data.claim||selected;toast('Vote recorded');await loadGraphStatus();await loadClaims(false);await selectClaim(selected.id)}catch(e){toast(e.message||'Vote route not wired yet')}}
async function saveClaim(){const body={claim:document.getElementById('cClaim').value,category:document.getElementById('cCategory').value,type:document.getElementById('cType').value,initialEvidence:document.getElementById('cEvidence').value};try{const data=await api('/api/claims',{method:'POST',body:JSON.stringify(body)});selected=data.claim;await loadGraphStatus();await loadClaims(false);if(data.existing){toast('This claim already exists.');document.getElementById('main').innerHTML=`<div class="panel form-panel"><span class="badge b-blue">already exists</span><h2>Claim already exists</h2><p class="small">A claim with the same meaning is already in the system.</p><p class="small"><b>${esc(cleanClaimLabel(selected.claim))}</b></p><div class="actions"><button class="primary" onclick="selectClaim('${esc(selected.id)}')">Study existing claim</button><button onclick="setMode('submit')">Submit a different claim</button><button onclick="setMode('arena')">Browse Claims</button></div></div>`}else{toast('Claim submitted for Review. It will appear publicly after approval.');document.getElementById('main').innerHTML=`<div class="panel form-panel"><span class="badge b-yellow">in review</span><h2>Claim submitted for Review</h2><p class="small">Your claim is now in the moderation queue and is not yet public. It will appear publicly after an admin approves it.</p><p class="small"><b>${esc(cleanClaimLabel(selected.claim))}</b></p><div class="actions"><button class="primary" onclick="selectClaim('${esc(selected.id)}')">Study this claim</button><button onclick="setMode('submit')">Submit another</button><button onclick="setMode('arena')">Browse Claims</button></div></div>`}}catch(e){toast(e.message||'Claim submission failed.')}}
async function addCaseItem(){if(!selected)return toast('Select a claim first');const kind=document.getElementById('eKind').value;const payload={claimId:selected.id,title:document.getElementById('eTitle').value,quality:document.getElementById('eQuality').value,body:document.getElementById('eNote').value,sourceUrl:document.getElementById('eSource')?.value||''};try{const data=await api(kind==='evidence'?'/api/evidence':'/api/pressure',{method:'POST',body:JSON.stringify(payload)});selected=data.claim||selected;await loadGraphStatus();await selectClaim(selected.id);document.getElementById('eTitle').value='';document.getElementById('eNote').value='';if(document.getElementById('eSource'))document.getElementById('eSource').value='';toast(kind==='evidence'?'Evidence attached to selected claim.':'Attack / pressure attached to selected claim.')}catch(e){toast(e.message||'Evidence attach failed.')}}
async function addHomeTestUI(){if(!selected)return toast('Select a claim first');const title=(document.getElementById('testTitle')?.value||'').trim();const instructions=(document.getElementById('testInstructions')?.value||'').trim();if(!title)return toast('Enter a test title before adding.');if(instructions.length<8)return toast('Instructions need at least 8 characters — describe what to do and record.');const body={claimId:selected.id,title,instructions,safetyLevel:document.getElementById('testSafety')?.value||'low',difficulty:document.getElementById('testDifficulty')?.value||'easy'};try{await api('/api/tests',{method:'POST',body:JSON.stringify(body)});toast('Test added');await selectClaim(selected.id)}catch(e){toast(e.message||'Could not add test')}}
function reportSelected(){if(!selected)return toast('Select a claim first');const claimLabel=esc(cleanClaimLabel(selected.claim));hxModal({title:'Report Claim',body:`<p class="small" style="margin:0 0 4px;color:var(--text)">${claimLabel}</p><textarea id="hx-report-reason" placeholder="Why report this claim?" rows="3" style="width:100%;margin-top:6px;resize:vertical"></textarea>`,confirmLabel:'Send Report',onConfirm:close=>{const reason=(document.getElementById('hx-report-reason')?.value||'').trim();if(!reason)return;close();api('/api/report',{method:'POST',body:JSON.stringify({targetType:'claim',targetId:selected.id,reason})}).then(()=>loadGraphStatus()).then(()=>toast('Report sent')).catch(e=>toast(e.message||'Report failed'));}});}
async function convertTruth(truthId){try{const data=await api('/api/truth-to-claim',{method:'POST',body:JSON.stringify({truthId})});toast(data.existing?'Existing claim opened in Study.':'Claim created from truth and sent to Review.');mode='arena';document.querySelectorAll('.tab').forEach(x=>x.classList.remove('active'));document.getElementById('tab-arena')?.classList.add('active');await loadGraphStatus();await loadClaims(false);if(data.bridge?.claimId)await selectClaim(data.bridge.claimId)}catch(e){toast(e.message||'Truth-to-claim conversion failed.')}}
async function generateRunPack(){if(!selected)return toast('Open a claim first');try{const data=await api('/api/runpack',{method:'POST',body:JSON.stringify({claimId:selected.id})});lastPacket=JSON.stringify(data.packet,null,2);lastPacketIsFallback=false}catch(e){lastPacket=JSON.stringify({runpack_version:'1.1',legacy_aip_version:'1.1',aip_version:'1.1',packet_type:'runpack_task',app:'HumanX',mode:'claim-pressure-analysis',no_owner_api_used:true,payload:selected},null,2);lastPacketIsFallback=true}lastPacketClaimId=selected.id;const statusEl=document.getElementById('aip-status');if(statusEl){statusEl.textContent='RunPack ready — copy it here or open the RunPack tab for full JSON and download.';statusEl.classList.add('runpack-side-status-ready')}else{const out=document.getElementById('aip');if(out)out.textContent=lastPacket}if(mode==='export')renderExport();toast('RunPack ready — copy it into your AI')}
function patchEvidencePanel(){const tools=document.getElementById('side-tools');if(!tools)return;const kindSelect=document.getElementById('eKind');if(kindSelect&&!document.getElementById('evidence-kind-hint')){const hint=document.createElement('p');hint.id='evidence-kind-hint';hint.className='small evidence-kind-hint';hint.innerHTML='<b>Support</b> backs the claim. <b>Attack</b> challenges or contradicts it.';kindSelect.after(hint)}const attachBtn=tools.querySelector('button[onclick="addCaseItem()"]');if(attachBtn&&!document.getElementById('evidence-attach-note')){const note=document.createElement('p');note.id='evidence-attach-note';note.className='small review-first-note';note.style.marginTop='3px';note.textContent='Saved to selected claim. Visibility follows Review state.';attachBtn.after(note)}}
function patchRunPackPanel(){const aip=document.getElementById('aip');if(!aip)return;const status=document.createElement('div');status.id='aip-status';status.className='runpack-side-status small';status.textContent=lastPacket?(lastPacketIsFallback?'⚠ Fallback RunPack — backend unavailable. Copy with caution.':'RunPack ready — copy it here or open the RunPack tab for full JSON and download.'):'Build a RunPack, then copy it into any AI for pressure-testing.';if(lastPacket&&!lastPacketIsFallback)status.classList.add('runpack-side-status-ready');if(lastPacketIsFallback)status.classList.add('runpack-side-status-fallback');aip.replaceWith(status);const tools=document.getElementById('side-tools');if(!tools)return;for(const btn of tools.querySelectorAll('button')){if(btn.textContent.trim()==='Generate RunPack'){btn.textContent='Build RunPack';break}}if(!document.getElementById('runpack-side-note')){const actionsDiv=tools.querySelector('.actions');if(actionsDiv){const note=document.createElement('p');note.id='runpack-side-note';note.className='small review-first-note';note.textContent='Private working packet. Exporting does not publish anything.';actionsDiv.after(note)}}}
async function generateAIP(){return generateRunPack()}
async function copyAIP(){if(!lastPacket)await generateRunPack();navigator.clipboard.writeText(lastPacket);toast('RunPack copied')}
async function saveAnalysisResult(){if(!selected)return toast('Open a claim first');const box=document.getElementById('analysisPaste');const text=box?.value||'';let parsed;try{parsed=JSON.parse(text)}catch(e){return toast('Paste valid JSON first')}const result=parsed.output||parsed.result||parsed.analysis||parsed;try{await api('/api/analysis',{method:'POST',body:JSON.stringify({claimId:selected.id,source:'runpack-user',raw:result})});if(box)box.value='';toast('Analysis saved');await selectClaim(selected.id)}catch(e){toast(e.message||'Could not save analysis')}}
function downloadJSON(){const blob=new Blob([JSON.stringify({user,claims,evidenceVault,truths,beliefSnapshots,graphStatus},null,2)],{type:'application/json'});const a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='humanx-visible-data.json';a.click();URL.revokeObjectURL(a.href)}
function downloadRunPack(){if(!lastPacket)return toast('Build a RunPack first — click Build RunPack above.');const name='runpack-'+(selected?.id||'claim').slice(0,24)+'.json';const blob=new Blob([lastPacket],{type:'application/json'});const a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download=name;a.click();URL.revokeObjectURL(a.href);toast('RunPack downloaded')}
function renderError(e){document.getElementById('main').innerHTML=`<div class="panel"><h2>HumanX backend notice</h2><p class="small">${esc(e.message||e)}</p></div>`}
window.setMode=setMode;window.searchCurrent=searchCurrent;window.loadClaims=loadClaims;window.saveAdminTokenAndLoadReview=saveAdminTokenAndLoadReview;window.clearAdminToken=clearAdminToken;window.reviewDecisionUI=reviewDecisionUI;window.inspectReviewItem=inspectReviewItem;window.requestRejectReview=requestRejectReview;window.cancelRejectReview=cancelRejectReview;window.requestCleanupReview=requestCleanupReview;window.cancelCleanupReview=cancelCleanupReview;window.reviewCleanupUI=reviewCleanupUI;window.toggleReviewAudit=toggleReviewAudit;window.openReviewClaimStudy=openReviewClaimStudy;window.studyFromVault=studyFromVault;window.setReviewFilter=setReviewFilter;window.selectClaim=selectClaim;window.saveClaim=saveClaim;window.updateClaimTypeHint=updateClaimTypeHint;window.setCatChip=setCatChip;window.addCaseItem=addCaseItem;window.addHomeTestUI=addHomeTestUI;window.reportSelected=reportSelected;window.generateAIP=generateAIP;window.generateRunPack=generateRunPack;window.copyAIP=copyAIP;window.downloadJSON=downloadJSON;window.downloadRunPack=downloadRunPack;window.patchRunPackPanel=patchRunPackPanel;window.patchEvidencePanel=patchEvidencePanel;window.voteClaim=voteClaim;window.backToArena=backToArena;window.submitTruth=submitTruth;window.convertTruth=convertTruth;window.attachEvidencePrompt=attachEvidencePrompt;window.doAttachEvidence=doAttachEvidence;window.closeAttachModal=closeAttachModal;window.saveBeliefMirror=saveBeliefMirror;window.beliefPreview=beliefPreview;window.promoteBelief=promoteBelief;window.saveAnalysisResult=saveAnalysisResult;
boot();
